 local oldIsFreezing = nil local oldIsOverheating = nil local oldOnUpdate = nil local function IsFreezing(self, ...) local immunity = self.inst:GetCharacterBonus( "undercoolimmunity" ) > 0x0 or self.inst:GetCharacterBonus( "sacreddefense" ) > 0x0 if immunity then return false end if oldIsFreezing then return oldIsFreezing(self, ...) end return false end local function IsOverheating(self, ...) local immunity = self.inst:GetCharacterBonus( "overheatimmunity" ) > 0x0 or self.inst:GetCharacterBonus( "sacreddefense" ) > 0x0 if immunity then return false end if oldIsOverheating then return oldIsOverheating(self, ...) end return false end local function OnUpdate(self, dt, applyhealthdelta, ...) local temp = self.current or 0x23 local temp1 = self.overheattemp or 0x46 local immunity = self.inst:GetCharacterBonus( "sacreddefense" ) > 0x0 or (temp >= temp1 and self.inst:GetCharacterBonus( "overheatimmunity" ) > 0x0) or (temp <= 0x0 and self.inst:GetCharacterBonus( "undercoolimmunity" ) > 0x0) if immunity then applyhealthdelta = false end if oldOnUpdate then return oldOnUpdate(self, dt, applyhealthdelta, ...) end end local function DYCTemperature(self) oldIsFreezing = self.IsFreezing self.IsFreezing = IsFreezing oldIsOverheating = self.IsOverheating self.IsOverheating = IsOverheating oldOnUpdate = self.OnUpdate self.OnUpdate = OnUpdate end return DYCTemperature 